        <form class="card" method="post" action="<?= base_url($basePath . '/terceros') ?>"><?= csrf_field() ?><h3 style="margin-top:0">Alta y test de rol</h3><label>Entidad</label><input name="nombre" required><label>NIT o identificacion</label><input name="documento" required><label>Pais contractual</label><input name="pais" value="Colombia" required><label>Correo de contacto</label><input type="email" name="contacto_email"><h4>Representacion</h4><label>Representante</label><input name="representante_nombre" required><label>Documento del representante</label><input name="representante_documento" required><label>Correo del representante</label><input type="email" name="representante_email" required><label>Evidencia de facultades</label><input name="representacion_evidencia" required><label><input type="checkbox" name="facultades_verificadas" value="1"> Facultades verificadas</label><h4>Test material por operacion</h4><div class="checks"><label><input type="checkbox" name="rol_accede_datos" value="1"> Accede o puede acceder a datos</label><label><input type="checkbox" name="rol_decide_finalidades" value="1"> Decide finalidades</label><label><input type="checkbox" name="rol_decide_medios" value="1"> Decide medios esenciales</label><label><input type="checkbox" name="rol_obligacion_propia" value="1"> Trata por obligacion legal propia</label><label><input type="checkbox" name="rol_fines_propios" value="1"> Usa datos para fines propios</label><label><input type="checkbox" name="rol_solo_instrucciones" value="1"> Opera tambien bajo instrucciones documentadas</label></div><label>Delimitacion de operaciones si existe rol dual</label><textarea name="operaciones_rol_dual"></textarea><label>Justificacion de la clasificacion</label><textarea name="clasificacion_justificacion" required></textarea><h4>Contrato y alcance</h4><label>Referencia contrato principal</label><input name="contrato_principal_ref" required><label>Objeto del contrato principal</label><textarea name="contrato_principal_objeto" required></textarea><label>Servicio detallado, minimo 50 caracteres</label><textarea name="servicio" minlength="50" required></textarea><label>Fecha del contrato</label><input type="date" name="contrato_fecha" required><label>Vencimiento</label><input type="date" name="contrato_vence" required><label>Evidencia contractual</label><input name="contrato_evidencia" required><label>Bases</label><select name="bases[]" multiple size="6" required><?php foreach($bases as $base): ?><option value="<?= $base['id'] ?>"><?= esc($base['nombre']) ?></option><?php endforeach; ?></select><label>Finalidades</label><select name="finalidades[]" multiple size="6" required><?php foreach($finalidades as $purpose): ?><option value="<?= $purpose['id'] ?>"><?= esc($purpose['descripcion']) ?></option><?php endforeach; ?></select><label>Titulares</label><div class="checks"><?php foreach(['propietarios','residentes','visitantes','empleados','proveedores','menores'] as $v): ?><label><input type="checkbox" name="titulares[]" value="<?= $v ?>"> <?= $v ?></label><?php endforeach; ?></div><label>Categorias</label><div class="checks"><?php foreach(['identificacion','contacto','financieros','laborales','imagen_video','salud','biometricos','menores'] as $v): ?><label><input type="checkbox" name="categorias[]" value="<?= $v ?>"> <?= str_replace('_',' ',$v) ?></label><?php endforeach; ?></div><label>Operaciones</label><div class="checks"><?php foreach(['recoleccion','registro','consulta','almacenamiento','actualizacion','circulacion','supresion','soporte','envio_correo','analisis_ia','cctv','biometria'] as $v): ?><label><input type="checkbox" name="operaciones[]" value="<?= $v ?>"> <?= str_replace('_',' ',$v) ?></label><?php endforeach; ?></div><label>Sistemas y soportes, separados por coma</label><input name="sistemas" required><label>Paises propios y de subencargados, separados por coma</label><input name="paises" value="Colombia" required><label><input type="checkbox" name="usa_videovigilancia" value="1"> Trata videovigilancia</label><h4>Debida diligencia y seguridad</h4><label>Nivel inicial de riesgo</label><select name="nivel_riesgo"><option>basico</option><option>medio</option><option>alto</option></select><div class="checks"><?php foreach(['control_acceso','tls','backups_cifrados','capacitacion','no_resucitar','mfa','cifrado_reposo','logs','segregacion','restauracion','vulnerabilidades','continuidad','destruccion_doble_verificacion'] as $v): ?><label><input type="checkbox" name="medidas[]" value="<?= $v ?>"> <?= str_replace('_',' ',$v) ?></label><?php endforeach; ?></div><label>Informe de debida diligencia</label><input name="debida_diligencia_evidencia" required><label><input type="checkbox" name="medidas_verificadas" value="1"> Medidas verificadas</label><label><input type="checkbox" name="canal_incidentes_probado" value="1"> Canal de incidentes probado</label><label>Plazo de incidente, dias habiles</label><input type="number" min="1" max="3" name="plazo_incidente_dias" value="3"><label>Retencion de logs, meses</label><input type="number" min="6" name="logs_retencion_meses" value="12"><label>Rotacion de respaldos, dias</label><input type="number" min="1" max="365" name="backup_rotacion_dias" value="90"><label>RTO horas</label><input type="number" min="1" name="rto_horas" value="24"><label>RPO horas</label><input type="number" min="1" name="rpo_horas" value="24"><label>Seguro o garantia, requerido en riesgo medio/alto</label><input name="seguro_evidencia"><button class="btn btn-primary" type="submit">Guardar expediente sin habilitar</button></form></div>
