<script>
(function(){var buttons=[].slice.call(document.querySelectorAll('[data-pane]'));var panes=[].slice.call(document.querySelectorAll('.pane'));function openPane(name){buttons.forEach(function(b){b.classList.toggle('active',b.dataset.pane===name)});panes.forEach(function(p){p.classList.toggle('active',p.id==='pane-'+name)});history.replaceState(null,'','#'+name)}buttons.forEach(function(b){b.addEventListener('click',function(){openPane(b.dataset.pane)})});var selected=location.hash.replace('#','');openPane(document.getElementById('pane-'+selected)?selected:'resumen')})();
(function(){document.querySelectorAll('.processor-sign-form').forEach(function(form){var canvas=form.querySelector('.processor-signature'),output=form.querySelector('.processor-signature-data'),clear=form.querySelector('.processor-signature-clear'),ctx=canvas.getContext('2d'),drawing=false,dirty=false;var rect=canvas.getBoundingClientRect();canvas.width=rect.width*devicePixelRatio;canvas.height=150*devicePixelRatio;ctx.scale(devicePixelRatio,devicePixelRatio);ctx.lineWidth=2;ctx.lineCap='round';function point(e){var r=canvas.getBoundingClientRect();return{x:e.clientX-r.left,y:e.clientY-r.top}}canvas.addEventListener('pointerdown',function(e){drawing=true;dirty=true;var p=point(e);ctx.beginPath();ctx.moveTo(p.x,p.y)});canvas.addEventListener('pointermove',function(e){if(!drawing)return;var p=point(e);ctx.lineTo(p.x,p.y);ctx.stroke()});window.addEventListener('pointerup',function(){drawing=false});clear.addEventListener('click',function(){ctx.clearRect(0,0,canvas.width,canvas.height);dirty=false});form.addEventListener('submit',function(){output.value=dirty?canvas.toDataURL('image/png'):''})})})();
</script>
</body></html>
